const TimeGlyph* findGlyph(uint32_t letter) {
  for (size_t i = 0; i < sizeof(glyphs) / sizeof(glyphs[0]); i++) {
    if (glyphs[i].codepoint == letter) {
      return &glyphs[i];
    }
  }
  return nullptr;
}

bool getGlyphDsc(const lv_font_t*, lv_font_glyph_dsc_t* dsc, uint32_t letter, uint32_t) {
  if (dsc == nullptr) {
    return false;
  }

  const TimeGlyph* glyph = findGlyph(letter);
  if (glyph == nullptr) {
    return false;
  }

  memset(dsc, 0, sizeof(*dsc));
  dsc->adv_w = glyph->advW;
  dsc->box_w = glyph->boxW;
  dsc->box_h = glyph->boxH;
  dsc->ofs_x = glyph->ofsX;
  dsc->ofs_y = glyph->ofsY;
  dsc->stride = glyph->stride;
  dsc->format = LV_FONT_GLYPH_FORMAT_A8;
  dsc->gid.index = static_cast<uint32_t>(glyph - glyphs);
  return true;
}

const void* getGlyphBitmap(lv_font_glyph_dsc_t* dsc, lv_draw_buf_t*) {
  if (dsc == nullptr || dsc->gid.index >= sizeof(glyphs) / sizeof(glyphs[0])) {
    return nullptr;
  }

  const TimeGlyph& glyph = glyphs[dsc->gid.index];
  return glyphBitmap + glyph.bitmapIndex;
}

